const { ethers } = require('ethers');

class TokenSwapper {
  constructor(provider, signer, routerAddress) {
    this.provider = provider;
    this.signer = signer;
    this.routerAddress = routerAddress;
    this.router = new ethers.Contract(routerAddress, this.getRouterABI(), signer);
  }

  getRouterABI() {
    return [
      "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline) external returns (uint[] memory amounts)",
      "function getAmountsOut(uint amountIn, address[] calldata path) external view returns (uint[] memory amounts)",
      "function approve(address spender, uint256 amount) external returns (bool)"
    ];
  }

  getTokenABI() {
    return [
      "function balanceOf(address account) external view returns (uint256)",
      "function approve(address spender, uint256 amount) external returns (bool)",
      "function allowance(address owner, address spender) external view returns (uint256)"
    ];
  }

  async getAmountsOut(amountIn, tokenIn, tokenOut) {
    const path = [tokenIn, tokenOut];
    const amounts = await this.router.getAmountsOut(amountIn, path);
    return amounts;
  }

  async swapTokens(amountIn, tokenIn, tokenOut, recipient, slippage = 0.5) {
    try {
      const path = [tokenIn, tokenOut];
      const amounts = await this.getAmountsOut(amountIn, tokenIn, tokenOut);
      const amountOutMin = amounts[1].mul(100 - slippage * 100).div(100);
      const deadline = Math.floor(Date.now() / 1000) + 60 * 20; // 20 minutes

      const tx = await this.router.swapExactTokensForTokens(
        amountIn,
        amountOutMin,
        path,
        recipient,
        deadline
      );

      return await tx.wait();
    } catch (error) {
      throw new Error(`Swap failed: ${error.message}`);
    }
  }

  async approveToken(tokenAddress, amount = ethers.constants.MaxUint256) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, this.getTokenABI(), this.signer);
      const tx = await tokenContract.approve(this.routerAddress, amount);
      return await tx.wait();
    } catch (error) {
      throw new Error(`Approval failed: ${error.message}`);
    }
  }

  async checkAllowance(tokenAddress, spenderAddress) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, this.getTokenABI(), this.provider);
      const allowance = await tokenContract.allowance(await this.signer.getAddress(), spenderAddress);
      return allowance;
    } catch (error) {
      throw new Error(`Allowance check failed: ${error.message}`);
    }
  }

  async getBalance(tokenAddress) {
    try {
      const tokenContract = new ethers.Contract(tokenAddress, this.getTokenABI(), this.provider);
      const balance = await tokenContract.balanceOf(await this.signer.getAddress());
      return balance;
    } catch (error) {
      throw new Error(`Balance check failed: ${error.message}`);
    }
  }

  async ensureApproval(tokenAddress, amount) {
    try {
      const currentAllowance = await this.checkAllowance(tokenAddress, this.routerAddress);
      
      if (currentAllowance.lt(amount)) {
        const tx = await this.approveToken(tokenAddress, ethers.constants.MaxUint256);
        return await tx.wait();
      }
      
      return true;
    } catch (error) {
      throw new Error(`Approval check failed: ${error.message}`);
    }
  }

  async swapWithApproval(amountIn, tokenIn, tokenOut, recipient, slippage = 0.5) {
    try {
      await this.ensureApproval(tokenIn, amountIn);
      return await this.swapTokens(amountIn, tokenIn, tokenOut, recipient, slippage);
    } catch (error) {
      throw new Error(`Swap with approval failed: ${error.message}`);
    }
  }
}

module.exports = TokenSwapper;